import{_ as t,c as o,o as r,a1 as s}from"./chunks/framework.9hXSu8bi.js";const n="/mypatterndocs/static/%E5%AD%90%E9%A1%B9%E7%9B%AE%E4%BB%8B%E7%BB%8D.DzV99M4R.png",m=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"zh/帮助文档/功能介绍/子项目.md","filePath":"zh/帮助文档/功能介绍/子项目.md"}'),l={name:"zh/帮助文档/功能介绍/子项目.md"},i=s('<h2 id="子项目" tabindex="-1">子项目 <a class="header-anchor" href="#子项目" aria-label="Permalink to &quot;子项目&quot;">​</a></h2><blockquote><p>子项目页面用于管理具体的监测对象，支持查看基本信息、对子项目配置进行编辑。</p></blockquote><p><img src="'+n+'" alt="" data-fancybox="gallery"></p><h3 id="_1-子项目基本信息" tabindex="-1">1. 子项目基本信息 <a class="header-anchor" href="#_1-子项目基本信息" aria-label="Permalink to &quot;1. 子项目基本信息&quot;">​</a></h3><ul><li><strong>编号</strong>：子项目的唯一标识，系统自动生成。</li><li><strong>名称</strong>：自定义的子项目名称，用于区分不同监测区域或对象。</li><li><strong>状态</strong>：雷达当前运行状态，分为在线和离线两种状态。</li><li><strong>曲线预警类别</strong>：当前启用的曲线预警类别，分为单区预警和分区预警两种类别。</li><li><strong>最新数据时间</strong>：最近一次接收到监测数据的时间。</li><li><strong>创建时间</strong>：子项目的创建日期，由系统自动记录。</li><li><strong>当前步骤</strong>：子项目所处的业务流程阶段，例如待切片、已融合等。</li></ul><h3 id="_2-编辑子项目" tabindex="-1">2. 编辑子项目 <a class="header-anchor" href="#_2-编辑子项目" aria-label="Permalink to &quot;2. 编辑子项目&quot;">​</a></h3><ul><li><strong>新增</strong>：在当前项目下创建新的子项目。</li><li><strong>进入</strong>：跳转至该子项目的三维监测页面，查看三维场景和监测数据。</li><li><strong>编辑</strong>：修改子项目的名称和所属设备。</li><li><strong>删除</strong>：删除当前子项目。</li><li><strong>曲线配置</strong>：设置监测曲线的显示参数（如位移、速度等）和算法（如切线角法、逆速度法等）。</li><li><strong>地形融合</strong>：执行地形数据与雷达数据的坐标对齐与融合操作，生成三维监测基底。</li><li><strong>滤镜</strong>：用户可手动上传自己准备的滤镜。</li><li><strong>雷达数据</strong>：查看历史雷达在线率。</li><li><strong>运行参数</strong>：查看雷达的运行参数，如起始角度、观测近距、起始数据时间等。</li><li><strong>切换预警类别</strong>：更改子项目的预警类别，可以在“单区预警”和“分区预警”之间进行切换。</li><li><strong>结项</strong>：将子项目标记为结项，归档数据并停止监测（历史数据仍可查看）。</li></ul>',7),a=[i];function e(g,_,c,d,h,p){return r(),o("div",null,a)}const f=t(l,[["render",e]]);export{m as __pageData,f as default};
